// Compute a 28-day date range for the Search Analytics query.
const end = new Date();
const start = new Date(end.getTime() - 28 * 24 * 60 * 60 * 1000);
const fmt = (d) => d.toISOString().slice(0, 10);
return [{ json: { startDate: fmt(start), endDate: fmt(end) } }];

// Filter + rank striking-distance opportunities (avg position 8-20).
const MIN_POS = 8, MAX_POS = 20, MIN_IMPR = 20, LIMIT = 200;
const rows = $input.first().json.rows || [];
const out = rows
  .filter((r) => r.position >= MIN_POS && r.position <= MAX_POS && r.impressions >= MIN_IMPR)
  .map((r) => {
    const [query, page] = r.keys;
    const proximity = 1 - (r.position - MIN_POS) / (MAX_POS - MIN_POS || 1);
    const ctrHeadroom = 1 - Math.min(r.ctr, 0.5) / 0.5;
    const opportunityScore = Math.round(r.impressions * (0.6 * proximity + 0.4 * ctrHeadroom));
    return {
      query,
      page,
      impressions: r.impressions,
      clicks: r.clicks,
      ctr: Number((r.ctr * 100).toFixed(2)),
      position: Number(r.position.toFixed(1)),
      opportunityScore,
    };
  })
  .sort((a, b) => b.opportunityScore - a.opportunityScore)
  .slice(0, LIMIT);
return out.map((json) => ({ json }));
